package admin

import "time"

// User is the authenticated principal. Greenfield D-5 rename of
// AdminUser. The single-user invariant from Phase 7 is preserved by
// the repository's Get path (ORDER BY id ASC LIMIT 1), but the table
// is multi-row capable to unblock N-1 multi-user UI without another
// schema bump.
//
// AutoGenerated is in-memory only (no DB column post-D-5). The
// Bootstrap flow sets it true on a freshly auto-generated password
// so the WARN-log + return value to wiring stays meaningful; the
// repository never persists it. Handlers reading user.AutoGenerated
// after a Get see false — sufficient because the first-run
// password banner is communicated via the structured log on
// Bootstrap, and the auto-gen state is not a long-lived UI flag in
// the new shape.
type User struct {
	ID                uint
	Username          string
	Email             *string
	PasswordHash      string
	OIDCSubject       *string
	Role              string
	AvatarMode        string
	PreferredLanguage *string
	AutoGenerated     bool
	CreatedAt         time.Time
	UpdatedAt         time.Time
	LastLoginAt       *time.Time
}

const (
	RoleAdmin = "admin"
	RoleUser  = "user"

	AvatarModeAuto     = "auto"
	AvatarModeMonogram = "monogram"
	AvatarModeGravatar = "gravatar"
)
